# Terraform: MSK クラスターに対して mTLS を有効にする
resource "aws_msk_cluster" "<example_resource_name>" {
  cluster_name           = "<example_resource_name>"
  kafka_version          = "<example_kafka_version>"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    client_subnets = ["<subnet_id_1>", "<subnet_id_2>"]
  }

  client_authentication {
    tls {
      certificate_authority_arns = ["<acm_pca_arn>"]  # CRITICAL: このプライベート CA で相互 TLS を有効にします
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"  # CRITICAL: mTLS を有効にする際に必要です
    }
  }
}
